import constFlaskURL from "../hooks/constFlaskURL";

export const handleLogout = async () => {
    try {
        const response = await constFlaskURL.post('/logout');

        if (response.status === 200) {
                setTimeout(() => {}, 1000);
        }
    } catch (error) {
            console.error('Logout error:', error);
    }    
};
